--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8462,7 +8462,22 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       return new FCmpInst(FCmpInst::FCMP_UNO, Op0, ConstantFP::getZero(OpType),
                           "", &I);
     case FCmpInst::FCMP_UGE:
-      return new FCmpInst(FCmpInst::FCMP_UEQ, Op0, Op1, "", &I);
+      #include "llvm/Analysis/ValueTracking.h"
+
+if (auto *FPMathOp = dyn_cast<FPMathOperator>(Op0)) {
+  #include "llvm/Analysis/ValueTracking.h"
+
+if (FPMathOp->getFastMathFlags().noNaNs() &&
+    ((isa<ConstantFP>(Op0) && !cast<ConstantFP>(Op0)->isNaN()) ||
+    (isa<ConstantDataVector>(Op0) &&
+     all_of(cast<ConstantDataVector>(Op0)->operands(), [](Value *Elt) {
+       return isa<ConstantFP>(Elt) && !cast<ConstantFP>(Elt)->isNaN();
+     })) ||
+    isa<ConstantAggregateZero>(Op0))) {
+    return new FCmpInst(FCmpInst::FCMP_UEQ, Op0, Op1, "", &I);
+  }
+}
+return nullptr; // Skip transformation if LHS might be NaN
     }
   }

